import { createRouter, createWebHashHistory } from 'vue-router';
import layout from '../layout.vue';
import Home from '../views/Home.vue';
import MusicList from '../views/MusicList.vue';
import Dispute from '../views/Dispute.vue';
import Examine from '../views/Examine.vue';
import UserAgreement from '../views/agreement/UserAgreement.vue';
import TechnologyAgreement from '../views/agreement/TechnologyAgreement.vue';
import login from '../views/signin/index.vue';

const routes = [
  {
    path: '/login',
    component: login,
    hidden: true
  },
  {
    path: '/',
    name: 'App',
    redirect: '/home',
    component: layout,
    children: [
      {
        //音乐列表
        path: '/home',
        name: 'home',
        component: Home
      },
      {
        //音乐包
        path: '/musicList',
        name: 'musicList',
        component: MusicList
      },
      {
        //纠纷处理
        path: '/dispute',
        name: 'dispute',
        component: Dispute
      },
      {
        //自审制度
        path: '/examine',
        name: 'examine',
        component: Examine
      },
      {
        //用户权益保障制度
        path: '/userAgreement',
        name: 'userAgreement',
        component: UserAgreement
      },
      {
        //技术安全保障制度
        path: '/technologyAgreement',
        name: 'technologyAgreement',
        component: TechnologyAgreement
      }
    ]
  },
  // {
  //   path: '/',
  //   name: 'App',
  //   redirect: '/home',
  //   component: layout,
  // }

];


const router = createRouter({
  history: createWebHashHistory(process.env.BASE_URL),
  routes
});

router.beforeEach((to, from, next) => {
  console.log('beforeEach----1111111111111111');
  // 让页面回到顶部
  document.documentElement.scrollTop = 0;
  // 一定不要忘记调用 next()
  next();
});

export default router;
